import { getWithFallback, patchWithFallback, postWithFallback } from './http';

export type CustomerStatus = 'Ativo' | 'Suspenso';

export interface Customer {
  id: string;
  name: string;
  email: string;
  plan: string;
  status: CustomerStatus;
}

export interface CreateCustomerInput {
  name: string;
  email: string;
  plan: string;
  status: CustomerStatus;
}

export interface UpdateCustomerInput {
  name: string;
  email: string;
  plan: string;
  status: CustomerStatus;
}

let customersDb: Customer[] = [
  { id: '1', name: 'Ana Paula Nunes', email: 'ana.nunes@provedor.com', plan: '400 Mega', status: 'Ativo' },
  { id: '2', name: 'Bruno Oliveira', email: 'bruno.oliveira@provedor.com', plan: '600 Mega', status: 'Ativo' },
  { id: '3', name: 'Carla Mendes', email: 'carla.mendes@provedor.com', plan: '200 Mega', status: 'Suspenso' },
  { id: '4', name: 'Diego Santos', email: 'diego.santos@provedor.com', plan: '1 Giga', status: 'Ativo' },
  { id: '5', name: 'Erika Lima', email: 'erika.lima@provedor.com', plan: '400 Mega', status: 'Ativo' },
  { id: '6', name: 'Felipe Costa', email: 'felipe.costa@provedor.com', plan: '600 Mega', status: 'Suspenso' },
];

export const fetchCustomers = async (): Promise<Customer[]> => {
  return getWithFallback('/customers', () => [...customersDb], 250);
};

export const fetchCustomerById = async (id: string): Promise<Customer | null> => {
  return getWithFallback(`/customers/${id}`, () => {
    const found = customersDb.find((customer) => customer.id === id);
    return found || null;
  }, 180);
};

export const createCustomer = async (input: CreateCustomerInput): Promise<Customer> => {
  return postWithFallback('/customers', input, () => {
    const newCustomer: Customer = {
      id: String(Date.now()),
      name: input.name.trim(),
      email: input.email.trim(),
      plan: input.plan.trim(),
      status: input.status,
    };

    customersDb = [newCustomer, ...customersDb];
    return newCustomer;
  }, 220);
};

export const updateCustomer = async (id: string, input: UpdateCustomerInput): Promise<Customer | null> => {
  return patchWithFallback(`/customers/${id}`, input, () => {
    const index = customersDb.findIndex((customer) => customer.id === id);
    if (index < 0) {
      return null;
    }

    const updated: Customer = {
      ...customersDb[index],
      name: input.name.trim(),
      email: input.email.trim(),
      plan: input.plan.trim(),
      status: input.status,
    };

    customersDb = customersDb.map((customer) => (customer.id === id ? updated : customer));
    return updated;
  }, 220);
};
